def _load_config_keywords() -> dict[str, list[str]]:
    """Load keywords from the existing config file."""
    try:
        with open("config/keywords.yaml", encoding="utf-8") as f:
            data = yaml.safe_load(f)
        return data.get("keyword_groups", {})
    except Exception:
        return {}


def load_database(path: str = DB_PATH) -> list[Paper]:
    return load_papers_database(path)


def save_database(papers: list[Paper], path: str = DB_PATH) -> None:
    save_papers_database(papers, path)


def load_checkpoint() -> dict[str, Any]:
    path = Path(CHECKPOINT_PATH)
    if not path.exists():
        return {
            "last_run": None,
            "completed_queries": [],
            "pending_queries": [],
            "total_found": 0,
            "total_added": 0,
            "status": "not_started",
        }
    with open(path, encoding="utf-8") as f:
        return json.load(f)


def save_checkpoint(checkpoint: dict[str, Any]) -> None:
    path = Path(CHECKPOINT_PATH)
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(checkpoint, f, ensure_ascii=False, indent=2)


