def search_semantic_scholar_paginated(
    ss: SemanticScholarAPI, query: str, year_range: str, max_results: int
) -> list[Paper]:
    """Search Semantic Scholar with pagination using offset."""
    all_papers: list[Paper] = []
    page_size = min(100, max_results)
    offset = 0

    while offset < max_results:
        url = f"{ss.base_url}/paper/search"
        params = {
            "query": query,
            "limit": page_size,
            "offset": offset,
            "fields": ss.fields,
            "year": year_range,
        }

        data = ss._request_with_backoff(url, params)
        if not data:
            break

        items = data.get("data", [])
        if not items:
            break

        for item in items:
            try:
                paper = ss._parse_paper(item)
                if paper:
                    all_papers.append(paper)
            except Exception as e:
                logger.warning(f"Failed to parse paper: {e}")

        total_available = data.get("total", 0)
        offset += page_size

        if offset >= total_available or offset >= 1000:
            break

    return all_papers


def search_openalex_paginated(
    oa: OpenAlexAPI, query: str, from_date: str, to_date: str, max_results: int
) -> list[Paper]:
    """Search OpenAlex with cursor-based pagination."""
    all_papers: list[Paper] = []
    cursor = "*"
    page_size = min(50, max_results)
    fetched = 0

    while fetched < max_results:
        params: dict[str, Any] = {
            "search": query,
            "per_page": page_size,
            "sort": "publication_date:desc",
            "cursor": cursor,
            "filter": f"from_publication_date:{from_date},to_publication_date:{to_date}",
        }

        data = oa._get("/works", params)
        if not data:
            break

        results = data.get("results", [])
        if not results:
            break

        for item in results:
            try:
                paper = oa._parse_work(item)
                if paper:
                    all_papers.append(paper)
                    fetched += 1
            except Exception as e:
                logger.warning(f"Failed to parse OpenAlex work: {e}")

        meta = data.get("meta", {})
        next_cursor = meta.get("next_cursor")
        if not next_cursor or fetched >= max_results:
            break
        cursor = next_cursor

    return all_papers


def search_arxiv_paginated(arxiv: ArxivAPI, query: str, max_results: int) -> list[Paper]:
    """Search arXiv with start-based pagination."""
    all_papers: list[Paper] = []
    page_size = min(100, max_results)
    start = 0

    while start < max_results and start < 2000:
        import feedparser
        import requests as req

        cat_filter = " OR ".join(f"cat:{c}" for c in arxiv.categories)
        search_query = f"all:{query} AND ({cat_filter})"

        params = {
            "search_query": search_query,
            "start": start,
            "max_results": page_size,
            "sortBy": "submittedDate",
            "sortOrder": "descending",
        }

        arxiv._wait_rate_limit()
        try:
            resp = req.get(arxiv.base_url, params=params, timeout=30)
            resp.raise_for_status()
        except req.RequestException as e:
            logger.error(f"arXiv request error: {e}")
            break

        feed = feedparser.parse(resp.text)
        entries = feed.entries
        if not entries:
            break

        for entry in entries:
            try:
                paper = arxiv._parse_entry(entry)
                if paper:
                    all_papers.append(paper)
            except Exception as e:
                logger.warning(f"Failed to parse arXiv entry: {e}")

        start += page_size
        if len(entries) < page_size:
            break

    return all_papers


